public void testRemoveDuplicateVarDeclarationsWithNestedFunctions() {
  test("function f(){} var f = function() { return 1; };",
       "function f(){} f = function() { return 1; };");
  test("if (true) { var f = 1; function f(){} }",
       "if (true) { f = 1; function f(){} }");
}

public void testMoveFunctionsWithLabelsAndBlocks() throws Exception {
  test("function f() { while(true) { a:function bar() {} } }",
       "function f() { for(;;) { a:{ var bar = function () {} } } }");
  test("function f() { { a:function bar() {} } }",
       "function f() { { a:{ var bar = function () {} } } }");
}

public void testFunctionDeclarationRedeclarationEdgeCases() {
  test("function f(){} if (a) { var f = 1; }",
       "function f(){} if (a) { f = 1; }");
  test("var f = 1; if (a) { function f(){} }",
       "f = 1; if (a) { var f = function (){} }");
}
